commands:
sudo tee /etc/nginx/sites-available/budol-ws <<'EOF'
server {
    listen 80;
    server_name budolws.duckdns.org;
    return 301 https://$host$request_uri;
}

server {
    listen 443 ssl;
    server_name budolws.duckdns.org;

    ssl_certificate /etc/letsencrypt/live/budolws.duckdns.org/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/budolws.duckdns.org/privkey.pem;

    location / {
        proxy_pass http://localhost:4000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_cache_bypass $http_upgrade;
    }
}
EOF
